  6	import {
  7	  Button,
  8	  ButtonVariant,
  9	  Flex,
 10	  FlexItem,
 11	  Form,
 12	  FormGroup,
 13	  FormHelperText,
 14	  HelperText,
 15	  HelperTextItem,
 16	  Modal,
 17	  ModalVariant,
 18	  TextInput,
 19	  TextInputTypes,
 20	  ValidatedOptions,
 21	} from '@patternfly/react-core';
 22	import { getValueValidations } from '../../utils/s3-iam';
 23	
 24	export type EditDescriptionTagModalProps = {
 25	  name: string;
 26	  AccessKeyId: string;
 27	  iamClient: IamCommands;
 28	  refreshTokens: () => void;
 29	};
 30	
 31	const EditDescriptionTagModal: React.FC<
 32	  CommonModalProps<EditDescriptionTagModalProps>
 33	> = ({
 34	  closeModal,
 35	  isOpen,
 36	  extraProps: { name, AccessKeyId, iamClient, refreshTokens },
 37	}) => {
 38	  const { t } = useCustomTranslation();
 39	  const [descriptionTagValue, setDescriptionTagValue] =
 40	    React.useState<string>('');
 41	  const [inProgress, setInProgress] = React.useState<boolean>(false);
 42	  const [error, setError] = React.useState<Error>();
 43	
 44	  const [validationVariant, helperText] = getValueValidations(
 45	    descriptionTagValue,
 46	    t
 47	  );
 48	
 49	  const handleClose = () => {
 50	    if (!inProgress) {
 51	      closeModal();
 52	    }
 53	  };
 54	
 55	  const handleSubmit = async (
 56	    event: React.MouseEvent<HTMLButtonElement>
 57	  ): Promise<void> => {
 58	    event.preventDefault();
 59	
 60	    // Prevent submission if validation fails
 61	    if (validationVariant === ValidatedOptions.error) {
 62	      return;
 63	    }
 64	
 65	    setInProgress(true);
 66	    setError(undefined);
 67	
 68	    try {
 69	      await iamClient.tagUser({
 70	        UserName: name,
 71	        Tags: [
 72	          {
 73	            Key: AccessKeyId,
 74	            Value: descriptionTagValue,
 75	          },
 76	        ],
 77	      });
 78	      setInProgress(false);
 79	      closeModal();
 80	      refreshTokens?.();
 81	    } catch (err) {
 82	      setInProgress(false);
 83	      setError(err as Error);
 84	    }
 85	  };
 86	
 87	  return (
 88	    <Modal
 89	      variant={ModalVariant.medium}
 90	      isOpen={isOpen}
 91	      onClose={handleClose}
 92	      title={t('Edit description tag')}
 93	      description={
 94	        <div className="text-muted">
 95	          {t(
 96	            'Description tag will be attached to the access key for this user'
 97	          )}
 98	        </div>
 99	      }
100	      actions={[
101	        <ButtonBar
102	          className="pf-v6-u-w-100"
103	          inProgress={inProgress}
104	          errorMessage={error ? error?.message || JSON.stringify(error) : ''}
105	        >
106	          <Flex>
107	            <FlexItem>
108	              <Button
109	                variant={ButtonVariant.primary}
110	                onClick={handleSubmit}
111	                isLoading={inProgress}
112	                isDisabled={
113	                  validationVariant === ValidatedOptions.error || inProgress
114	                }
115	              >
116	                {t('Update')}
117	              </Button>
118	            </FlexItem>
119	            <FlexItem>
120	              <Button
121	                variant={ButtonVariant.plain}
122	                onClick={closeModal}
123	                isDisabled={inProgress}
124	              >
125	                {t('Cancel')}
126	              </Button>
127	            </FlexItem>
128	          </Flex>
129	        </ButtonBar>,
130	      ]}
131	    >
132	      <Form>
133	        <FormGroup label={t('Description tag')}>
134	          <TextInput
135	            type={TextInputTypes.text}
136	            placeholder={t('Input field')}
137	            value={descriptionTagValue}
138	            className="pf-v6-u-w-50"
139	            validated={validationVariant}
140	            onChange={(_event, value) => {
141	              setDescriptionTagValue(value);
142	            }}
143	          />
144	
145	          <FormHelperText>
146	            <HelperText>
147	              <HelperTextItem variant={validationVariant}>
148	                {helperText}
149	              </HelperTextItem>
150	            </HelperText>
151	          </FormHelperText>
152	        </FormGroup>
153	      </Form>
154	    </Modal>
155	  );
156	};
157	
158	export default EditDescriptionTagModal;

